// Read integers until -1, then print sum
import java.util.Scanner;

public class SumCalculator {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int sum = 0;
        int n = 0;

        while (n != -1) {
            n = sc.nextInt();
            if (n != -1) sum += n;
        }

        System.out.println("Sum: " + sum);
        sc.close();
    }
}

