public class Array2D {
    public static void main(String[] args) {
        int[][] nums = {
            {1, 2, 3},
            {4, 5, 6}
        };

        int sum = 0;
        for (int[] row : nums) {
            for (int val : row) {
                sum += val;
            }
        }

        System.out.println(sum);
    }
}

